import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';

// Fix for default marker icon
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.7.1/dist/images/marker-icon-2x.png',
  iconUrl: 'https://unpkg.com/leaflet@1.7.1/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.7.1/dist/images/marker-shadow.png',
});

const App = () => {
  const [reports, setReports] = useState([]);
  const [prediction, setPrediction] = useState(null);
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    pollutionType: '',
    severity: 'LOW',
    address: '',
    city: '',
    state: '',
    village: '',
    description: '',
    latitude: 40.7128,
    longitude: -74.0060
  });

  useEffect(() => {
    fetchReports();
  }, []);

  const fetchReports = async () => {
    try {
      const response = await axios.get('http://localhost:8080/api/reports');
      setReports(response.data);
    } catch (error) {
      console.error('Error fetching reports:', error);
    }
  };

  const handleSubmitReport = async (e) => {
    e.preventDefault();
    try {
      await axios.post('http://localhost:8080/api/reports', {
        ...formData,
        timestamp: new Date().toISOString()
      });
      alert('Report submitted successfully!');
      fetchReports();
    } catch (error) {
      console.error('Error submitting report:', error);
    }
  };

  const generatePrediction = async (location) => {
    setLoading(true);
    try {
      const response = await axios.post(`http://localhost:8080/api/predictions/generate?location=${location}&hour=12&day=1&severity=2`);
      setPrediction(response.data);
    } catch (error) {
      console.error('Error generating prediction:', error);
    }
    setLoading(false);
  };

  return (
    <div className="container">
      <header className="header">
        <h1>EarthPulse AI</h1>
      </header>
      <div className="main">
        <aside className="sidebar">
          <h2>Report Pollution</h2>
          <form onSubmit={handleSubmitReport} style={{ display: 'flex', flexDirection: 'column', gap: '5px', marginBottom: '20px' }}>
            <input type="text" placeholder="Pollution Type" value={formData.pollutionType} onChange={e => setFormData({...formData, pollutionType: e.target.value})} required />
            <select value={formData.severity} onChange={e => setFormData({...formData, severity: e.target.value})}>
              <option value="LOW">Low</option>
              <option value="MEDIUM">Medium</option>
              <option value="HIGH">High</option>
            </select>
            <input type="text" placeholder="Address" value={formData.address} onChange={e => setFormData({...formData, address: e.target.value})} required />
            <input type="text" placeholder="City" value={formData.city} onChange={e => setFormData({...formData, city: e.target.value})} required />
            <input type="text" placeholder="State" value={formData.state} onChange={e => setFormData({...formData, state: e.target.value})} required />
            <input type="text" placeholder="Village" value={formData.village} onChange={e => setFormData({...formData, village: e.target.value})} />
            <textarea placeholder="Description" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})}></textarea>
            <button type="submit" style={{ background: '#2e7d32', color: 'white', border: 'none', padding: '5px' }}>Submit Report</button>
          </form>
          <hr />
          <h2>Recent Reports</h2>
          {reports.map(report => (
            <div key={report.id} className={`report-card severity-${report.severity.toLowerCase()}`}>
              <strong>{report.pollutionType}</strong>
              <p>{report.address || report.location}, {report.city}, {report.state}</p>
              <small>{new Date(report.timestamp).toLocaleString()}</small>
            </div>
          ))}
          <hr />
          <h2>AI Prediction</h2>
          {prediction ? (
            <div className="prediction-box">
              <h3>AQI: {prediction.aqiValue} ({prediction.aqiRange})</h3>
              <p>Confidence: {prediction.confidencePercentage}%</p>
            </div>
          ) : (
            <button onClick={() => generatePrediction('New York')} disabled={loading}>
              {loading ? 'Predicting...' : 'Get Prediction for NY'}
            </button>
          )}
        </aside>
        <div className="map-container">
          <MapContainer center={[40.7128, -74.0060]} zoom={13} style={{ height: '100%', width: '100%' }}>
            <TileLayer
              url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
              attribution='&copy; <a href="http://osm.org/copyright">OpenStreetMap</a> contributors'
            />
            {reports.map(report => (
              <Marker key={report.id} position={[report.latitude, report.longitude]}>
                <Popup>
                  <strong>{report.pollutionType}</strong><br />
                  {report.description}
                </Popup>
              </Marker>
            ))}
          </MapContainer>
        </div>
      </div>
    </div>
  );
};

export default App;
